#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-28

# test-storybook-catalog-import.sh — smoke test for #1529
# Validates the Storybook → json-render catalog importer against the bundled fixture.

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"
SCRIPT="$PROJECT_ROOT/src/skills/json-render-catalog/scripts/storybook-to-catalog.mjs"
FIXTURE="$PROJECT_ROOT/src/skills/json-render-catalog/references/storybook-fixture.json"
SPEC="$PROJECT_ROOT/src/skills/json-render-catalog/references/storybook-import.md"

PASS=0
FAIL=0

check() {
  local name="$1"; shift
  if "$@" >/dev/null 2>&1; then
    echo "  PASS $name"
    PASS=$((PASS + 1))
  else
    echo "  FAIL $name"
    FAIL=$((FAIL + 1))
  fi
}

check_fails() {
  local name="$1"; shift
  if ! "$@" >/dev/null 2>&1; then
    echo "  PASS $name (correctly rejected)"
    PASS=$((PASS + 1))
  else
    echo "  FAIL $name (should have rejected but didn't)"
    FAIL=$((FAIL + 1))
  fi
}

echo "Storybook → catalog importer smoke tests (#1529)"
echo

echo "[artifacts]"
check "import script exists"        test -f "$SCRIPT"
check "import script is executable" test -x "$SCRIPT"
check "fixture exists"              test -f "$FIXTURE"
check "spec doc exists"             test -f "$SPEC"
echo

echo "[fixture validates]"
check "fixture passes --check" node "$SCRIPT" "$FIXTURE" --check
echo

# Generate and inspect output
TMP=$(mktemp -d)
trap "rm -rf $TMP" EXIT
PROJ=$(mktemp -d)
trap "rm -rf $TMP $PROJ" EXIT

echo "[generation]"
if node "$SCRIPT" "$FIXTURE" --out "$PROJ/src/genui/catalog.ts" --components "$PROJ/src/genui/components.tsx" --project-root "$PROJ" 2>"$TMP/err"; then
  echo "  PASS catalog + components emitted"
  PASS=$((PASS + 1))
else
  echo "  FAIL emission failed"
  cat "$TMP/err"
  FAIL=$((FAIL + 1))
fi

# Concrete content checks
check "catalog.ts header sentinel"       grep -q "AUTO-GENERATED from Storybook" "$PROJ/src/genui/catalog.ts"
check "catalog.ts imports defineCatalog" grep -q "import { defineCatalog }" "$PROJ/src/genui/catalog.ts"
check "catalog.ts has 5 components"      bash -c "grep -cE '^  [A-Z][A-Za-z]+: \\{' '$PROJ/src/genui/catalog.ts' | grep -q '^5\$'"
check "catalog.ts has z.enum for select" grep -q "z.enum(\\['flat', 'low', 'high'\\])" "$PROJ/src/genui/catalog.ts"
check "catalog.ts has color regex"       grep -q "z.string().regex" "$PROJ/src/genui/catalog.ts"
check "catalog.ts has number bounds"     grep -q "z.number().min(0).max(1000000)" "$PROJ/src/genui/catalog.ts"
check "catalog.ts marks Card children"   grep -q "Card:" "$PROJ/src/genui/catalog.ts"
check "components.tsx relative imports"  grep -qE "from '\\.\\./components/[A-Z][a-z]+/[A-Z][a-z]+'" "$PROJ/src/genui/components.tsx"
echo

echo "[AI safety — drops]"
check "drops Button.onClick (callback)"  bash -c "node '$SCRIPT' '$FIXTURE' --json 2>&1 | grep -qF 'Button.onClick'"
check "drops RawJson.data (object)"      bash -c "node '$SCRIPT' '$FIXTURE' --json 2>&1 | grep -qF 'RawJson.data'"
# Make sure the dropped props really aren't in the catalog
TMP_CAT="$TMP/check.ts"
node "$SCRIPT" "$FIXTURE" --out "$TMP_CAT" --project-root "$PROJ" 2>/dev/null
check "Button.onClick not in catalog"    bash -c "! grep -q 'onClick' '$TMP_CAT'"
check "RawJson.data not in catalog"      bash -c "! grep -A 5 'RawJson:' '$TMP_CAT' | grep -q 'data:'"
check "no z.any() in catalog"            bash -c "! grep -qE 'z\\.any|z\\.unknown' '$TMP_CAT'"
echo

# Negative cases
echo "[invalid manifests]"
echo '{}' > "$TMP/empty.json"
check_fails "rejects manifest without components"   node "$SCRIPT" "$TMP/empty.json" --check

echo '{"components": []}' > "$TMP/no-comps.json"
check_fails "rejects empty components list"         node "$SCRIPT" "$TMP/no-comps.json" --check

echo '{"components":[{"name":"badname-with-dash","argTypes":{}}]}' > "$TMP/bad-name.json"
check_fails "rejects non-PascalCase name"           node "$SCRIPT" "$TMP/bad-name.json" --check
echo

echo "─── Results ───"
echo "  PASS: $PASS"
echo "  FAIL: $FAIL"
echo

if [[ $FAIL -gt 0 ]]; then exit 1; fi
exit 0
